      const dia = Number(fechaTexto[1]);
      const mes = meses[fechaTexto[2]];
      const anio = fechaTexto[3] ? Number(fechaTexto[3]) : base.year;

      if (!mes) return "";

      fecha = base.set({
        year: anio,
        month: mes,
        day: dia
      });
    }
  }

  const horaTexto =
    txt.match(/(?:a\s+las|a\s+la|las|la|hora|hrs?|horas?)\s*(\d{1,2})(?:(?:[:.](\d{2}))|\s+y\s+(media|cuarto|\d{1,2}))?/) ||
    txt.match(/\b(\d{1,2})(?:(?:[:.](\d{2}))|\s+y\s+(media|cuarto|\d{1,2}))\b/);

  if (!fecha || !horaTexto) return "";

  let hh = Number(horaTexto[1]);
  let mm = 0;

  if (horaTexto[2]) {
    mm = Number(horaTexto[2]);
  } else if (horaTexto[3]) {
    if (horaTexto[3] === "media") {
      mm = 30;
    } else if (horaTexto[3] === "cuarto") {
      mm = 15;
    } else {
      mm = Number(horaTexto[3]);
    }
  }

  const esPM = /\b(pm|p\.m\.|de\s+la\s+tarde|en\s+la\s+tarde|por\s+la\s+tarde|tarde)\b/.test(txt);
  const esAM = /\b(am|a\.m\.|de\s+la\s+manana|en\s+la\s+manana|por\s+la\s+manana)\b/.test(txt);

